#############################################################
# Business logic
#############################################################

def check_if_smallest_pqr (n, v):
    global smallest_pqr

    if n not in smallest_pqr:
        smallest_pqr[n] = v
    else:
        v1 = smallest_pqr[n]
        if v < v1:
            smallest_pqr[n] = v

def calculate_metrics ():
    global smallest_pqr, list_prime_nums, list_min_pqr_nums, list_ratio_prime_to_min_pqr

    smallest_pqr_sorted = dict(sorted(smallest_pqr.items()))
    for mkey, mvalue in smallest_pqr_sorted.items():
        list_prime_nums.append (mkey)
        list_min_pqr_nums.append (mvalue)
        list_ratio_prime_to_min_pqr.append (mkey/mvalue)

#############################################################
# Presentation
#############################################################

def write_results_to_figures ():
    global list_prime_nums, list_min_pqr_nums, list_ratio_prime_to_min_pq

    fig = plt.figure(1)
    plt.clf()
    plt.plot(list_prime_nums, list_min_pqr_nums, 'b', ms=1)
    fig.suptitle("Minimum pxqxr", fontsize=10)
    plt.savefig(file_output_fig1)
    plt.close(fig)

    fig = plt.figure(2)
    plt.clf()
    plt.plot(list_prime_nums, list_ratio_prime_to_min_pqr, 'b', ms=1)
    fig.suptitle("Ratio prime to minimum pxqxr", fontsize=10)
    plt.savefig(file_output_fig2)
    plt.close(fig)

#############################################################
# Main
#############################################################

print ("Initialize objects...")
p = primes.Primes(caching_primality_results)
c = calculations.Calculations()
g = graphs.Graphs()
print ("DONE")
print ("Loading helper sets...")
p.init_set(file_input_primes, True)
p.init_set(file_input_nonprimes, False)
print ("DONE")
print ("Sorting primes...")
p.sort_primes_set()
print ("DONE")

# new calculations
for pi in range (min_num, max_num):
    for qi in range (min_num, max_num):
        for ri in range (min_num, max_num):
            pn = p.get_ith_prime (pi)
            qn = p.get_ith_prime (qi)
            rn = p.get_ith_prime (ri)
            n1 = pn*qn + rn
            n2 = pn*qn - rn
            pqr = abs(pn*qn*rn)
            if p.is_prime (n1):
                check_if_smallest_pqr (n1, pqr)
            if p.is_prime (n2):
                check_if_smallest_pqr (n2, pqr)

smallest_pqr_sorted = dict(sorted(smallest_pqr.items()))
print (smallest_pqr_sorted)

f = open(file_output_pqr_sorted,'w')
print(smallest_pqr_sorted, file=f)

calculate_metrics ()
write_results_to_figures ()